const { DEVICE_TYPES } = require('../../constants/device');
const {
  DEVICE_TYPE_REGEX,
  FILE_WITH_DEVICE_SPECIFIED_REGEX,
} = require('../../constants/regexs');

/**
 * @typedef { keyof DEVICE_TYPES } DeviceType
 */

/**
 * @param { string } filePath - File path to analize
 * @returns { DeviceType | undefined } Device type found
 *
 * @example
 * getFileDeviceType('home.ts') => DEVICE_TYPES.base
 * getFileDeviceType('home.mobile.js') => 'mobile'
 */
const getFileDeviceType = (filePath) => {
  if (!FILE_WITH_DEVICE_SPECIFIED_REGEX.test(filePath)) {
    return DEVICE_TYPES.base;
  }

  const splittedFile = filePath.split('.');

  return DEVICE_TYPES[
    splittedFile.find((split) => DEVICE_TYPE_REGEX.test(split))
  ];
};

module.exports = { getFileDeviceType };
